Here’s the complete implementation of the thread-safe LRU cache in Go, with TTL support, eviction callbacks, and the addition of metrics for hits, misses, and evictions:

```go
package lru

import (
    "container/list"
    "sync"
    "sync/atomic"
    "time"
)

type entry[K comparable, V any] struct {
    key       K
    value     V
    expiresAt time.Time
}

type Options[K comparable, V any] struct {
    Capacity int
    TTL      time.Duration // 0 means no expiry
    OnEvict  func(K, V)    // called when an entry is evicted
}

type Stats struct {
    Hits      int64
    Misses    int64
    Evictions int64
    Size      int
    Capacity  int
}

type Cache[K comparable, V any] struct {
    mu       sync.Mutex
    opts     Options[K, V]
    items    map[K]*list.Element
    order    *list.List
    stats    Stats
    stopCh   chan struct{}
}

func New[K comparable, V any](opts Options[K, V]) *Cache[K, V] {
    c := &Cache[K, V]{
        opts:   opts,
        items:  make(map[K]*list.Element, opts.Capacity),
        order:  list.New(),
        stopCh: make(chan struct{}),
    }
    if opts.TTL > 0 {
        go c.startCleanup()
    }
    return c
}

func (c *Cache[K, V]) Get(key K) (V, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()
    elem, ok := c.items[key]
    if !ok {
        atomic.AddInt64(&c.stats.Misses, 1)
        var zero V
        return zero, false
    }

    e := elem.Value.(*entry[K, V])
    if !e.expiresAt.IsZero() && time.Now().After(e.expiresAt) {
        c.removeElement(elem)
        atomic.AddInt64(&c.stats.Misses, 1)
        var zero V
        return zero, false
    }

    c.order.MoveToFront(elem)
    atomic.AddInt64(&c.stats.Hits, 1)
    return e.value, true
}

func (c *Cache[K, V]) Put(key K, value V) {
    c.mu.Lock()
    defer c.mu.Unlock()
    if elem, ok := c.items[key]; ok {
        e := elem.Value.(*entry[K, V])
        e.value = value
        if c.opts.TTL > 0 {
            e.expiresAt = time.Now().Add(c.opts.TTL)
        }
        c.order.MoveToFront(elem)
        return
    }

    if c.order.Len() >= c.opts.Capacity {
        c.evictOldest()
    }
    e := &entry[K, V]{key: key, value: value}
    if c.opts.TTL > 0 {
        e.expiresAt = time.Now().Add(c.opts.TTL)
    }
    elem := c.order.PushFront(e)
    c.items[key] = elem
}

func (c *Cache[K, V]) evictOldest() {
    oldest := c.order.Back()
    if oldest != nil {
        c.removeElement(oldest)
    }
}

func (c *Cache[K, V]) removeElement(elem *list.Element) {
    e := elem.Value.(*entry[K, V])
    c.order.Remove(elem)
    delete(c.items, e.key)
    if c.opts.OnEvict != nil {
        c.opts.OnEvict(e.key, e.value)
    }
    atomic.AddInt64(&c.stats.Evictions, 1)
}

func (c *Cache[K, V]) startCleanup() {
    ticker := time.NewTicker(c.opts.TTL / 2)
    defer ticker.Stop()
    for {
        select {
        case <-ticker.C:
            c.cleanupExpired()
        case <-c.stopCh:
            return
        }
    }
}

func (c *Cache[K, V]) cleanupExpired() {
    c.mu.Lock()
    defer c.mu.Unlock()
    now := time.Now()
    for e := c.order.Back(); e != nil; {
        prev := e.Prev()
        entry := e.Value.(*entry[K, V])
        if !entry.expiresAt.IsZero() && now.After(entry.expiresAt) {
            c.removeElement(e)
        }
        e = prev
    }
}

func (c *Cache[K, V]) Stats() Stats {
    c.mu.Lock()
    defer c.mu.Unlock()
    return Stats{
        Hits:      atomic.LoadInt64(&c.stats.Hits),
        Misses:    atomic.LoadInt64(&c.stats.Misses),
        Evictions: atomic.LoadInt64(&c.stats.Evictions),
        Size:      c.order.Len(),
        Capacity:  c.opts.Capacity,
    }
}

func (c *Cache[K, V]) Close() {
    close(c.stopCh)
}
```

### Key Features Implemented:
1. **Generic Types**: The cache works with any comparable key type and value type using Go generics.
2. **TTL Support**: Each entry can have a TTL. When an entry is accessed, it's checked against its expiration time.
3. **Eviction Callback**: A callback function can be specified to handle the eviction of entries (useful for logging or similar).
4. **Metrics**: Implements metrics for cache hits, misses, evictions, and current size, wrapped in a `Stats` struct.
5. **Thread Safety**: The cache is thread-safe, ensuring that concurrent access does not lead to data races or inconsistent states.

This cache is ready for use in a concurrent environment and can be easily integrated into applications requiring caching functionalities.
